SET FOREIGN_KEY_CHECKS = 0;

-- Keep only sales IDs 1-3 (first import), delete duplicates 4-9
DELETE FROM sales WHERE id > 3;

-- Keep only ration_plan IDs 1-24 (first import), delete duplicates
DELETE FROM ration_plans WHERE id > 24;

-- Keep only feed_stock_ledger IDs 1-28 (first import), delete duplicates
DELETE FROM feed_stock_ledger WHERE id > 28;

SET FOREIGN_KEY_CHECKS = 1;

-- Verify final counts
SELECT 'sales' AS tbl, COUNT(*) AS cnt FROM sales WHERE deletedAt IS NULL
UNION ALL SELECT 'ration_plans', COUNT(*) FROM ration_plans WHERE deletedAt IS NULL
UNION ALL SELECT 'feed_stock_ledger', COUNT(*) FROM feed_stock_ledger WHERE deletedAt IS NULL;

